import pandas as pd
import json

# Il DataFrame df arriva automaticamente dal nodo SQL upstream
if df.empty:
    result = "<div style='padding:20px;color:red;'>❌ Il DataFrame di input è vuoto. Assicurati che il nodo SQL upstream sia collegato.</div>"
else:
    # FILTRO: Togli i clienti che contengono "QUID"
    df = df[~df['CLIENTE'].str.contains('QUID', case=False, na=False)]

    if df.empty:
        result = "<div style='padding:20px;color:orange;'>⚠️ Nessun dato dopo il filtro. Tutti i clienti contengono 'QUID'.</div>"
    else:
        # Conversioni numeriche
        df['markup'] = pd.to_numeric(df['MARKUP %'], errors='coerce').fillna(0)
        df['peso'] = pd.to_numeric(df['IMPONIBILE ORDINATO'], errors='coerce').fillna(0)
        df['prezzo_unitario'] = pd.to_numeric(df['PREZZO UNITARIO'], errors='coerce').fillna(0)
        df['costo_unitario'] = pd.to_numeric(df['COSTO BUDGET UNITARIO'], errors='coerce').fillna(0)
        df['quantita'] = pd.to_numeric(df['Q.TÀ ORDINATA'], errors='coerce').fillna(0)
        df['stato'] = df['STATO SCHEDA COSTI']

        # Raggruppo per COMMESSA CLIENTE (una riga per commessa)
        grouped = df.groupby('COMMESSA CLIENTE').agg({
            'CLIENTE': 'first',
            'ARTICOLO': lambda x: ' + '.join(x.unique()[:2]),
            'DESCRIZIONE': lambda x: ' + '.join(x.unique()[:2]),
            'markup': lambda x: (x * df.loc[x.index, 'peso']).sum() / df.loc[x.index, 'peso'].sum() if df.loc[x.index, 'peso'].sum() > 0 else 0,
            'peso': 'sum',
            'prezzo_unitario': 'mean',
            'costo_unitario': 'mean',
            'quantita': 'sum',
            'stato': 'first'
        }).reset_index()

        # Creo l'etichetta
        grouped['etichetta'] = grouped['COMMESSA CLIENTE'] + ' / ' + grouped['CLIENTE'].str[:25]

        # Preparo i dati per il JSON con tutte le info per il tooltip
        data_for_json = []
        for idx, row in grouped.iterrows():
            data_for_json.append({
                'etichetta': row['etichetta'],
                'articolo': row['ARTICOLO'],
                'descrizione': row['DESCRIZIONE'],
                'markup': round(row['markup'], 2),
                'peso': round(row['peso'], 2),
                'prezzo': round(row['prezzo_unitario'], 2),
                'costo': round(row['costo_unitario'], 2),
                'quantita': int(row['quantita']),
                'stato': row['stato']
            })

        # Converto a JSON
        json_data = json.dumps(data_for_json, ensure_ascii=False)

        # Calcolo imponibile affidabile in milioni
        reliableRows = df[df['STATO SCHEDA COSTI'] != 'ERROR']
        totalImponibile = reliableRows['IMPONIBILE ORDINATO'].sum()
        imponibile_milioni = totalImponibile / 1_000_000

        # Template HTML (vedi sotto)
        html_template = f"""<!DOCTYPE html>
