        }}

        .container {{ max-width: 1400px; margin: 0 auto; }}

        /* ── Section ── */
        .section {{ margin-bottom: 44px; }}
        .section-header {{
            display: flex;
            align-items: center;
            gap: 14px;
            margin-bottom: 20px;
            padding-bottom: 12px;
            border-bottom: 2px solid #c4d8ee;
        }}
        .section-title {{
            font-size: 15px;
            font-weight: 600;
            color: #0d2e52;
            letter-spacing: 0.2px;
            text-transform: uppercase;
        }}

        /* ── KPI Grid ── */
        .grid-4 {{
            display: grid;
            grid-template-columns: repeat(4, 1fr);
            gap: 20px;
            margin-bottom: 20px;
        }}
        .kpi-box {{
            background: #ffffff;
            border-radius: 12px;
            padding: 28px 24px;
