<script>
const ALL_DATA = {json_data};
const IMPONIBILE_MILIONI = {imponibile_milioni};

const RAW_DATA = ALL_DATA.filter(d => d.stato !== 'ERROR');
let currentData = [...RAW_DATA];

function computeStats(data) {{
    const total    = data.length;
    const positive = data.filter(d => d.markup >= 0).length;
    const negative = data.filter(d => d.markup < 0).length;

    const totalAll   = ALL_DATA.length;
    const goodCount  = ALL_DATA.filter(d => d.stato !== 'ERROR').length;
    const reliable   = totalAll > 0 ? (goodCount / totalAll) * 100 : 0;

    document.getElementById('kpi-total').textContent    = total;
    document.getElementById('kpi-positive').textContent = positive;
    document.getElementById('kpi-negative').textContent = negative;

    const relEl = document.getElementById('kpi-reliable');
    relEl.innerHTML  = `${{reliable.toFixed(0)}}<span class="kpi-unit">%</span>`;
    relEl.className  = 'kpi-value' + (reliable >= 70 ? ' positive' : ' negative');

    const totalPeso = data.reduce((s, d) => s + (d.peso || 0), 0);
    const wavg      = totalPeso > 0
        ? data.reduce((s, d) => s + d.markup * (d.peso || 0), 0) / totalPeso
        : 0;

    const wavgEl = document.getElementById('kpi-wavg');
    wavgEl.innerHTML = `${{wavg.toFixed(1)}}<span class="kpi-unit">%</span>`;
    wavgEl.className = 'kpi-value' + (wavg < 0 ? ' negative' : ' positive');
    document.getElementById('kpi-art-count').textContent = total;

    const errorCount = ALL_DATA.filter(d => d.stato === 'ERROR').length;
    const odpCount   = ALL_DATA.filter(d => d.stato === 'ODP TO DO').length;
    document.getElementById('kpi-error').textContent = errorCount;
    document.getElementById('kpi-odp').textContent   = odpCount;

    // Imponibile affidabile in milioni di euro
    const imponibileEl = document.getElementById('kpi-imponibile');
    if (imponibileEl) {{
        imponibileEl.innerHTML = `${{IMPONIBILE_MILIONI.toFixed(2)}}<span class="kpi-unit">M€</span>`;
        imponibileEl.className = 'kpi-value positive';
    }}
}}

const COLOR_POS = '#34d399';
const COLOR_NEG = '#f87171';

function buildChart(data) {{
    if (!data.length) {{ Plotly.purge('markup-chart'); return; }}

    const MAX_LBL = 55;
    const allLabels = data.map(d =>
        d.etichetta.length > MAX_LBL ? d.etichetta.slice(0, MAX_LBL - 1) + '...' : d.etichetta
    );
    const allValues = data.map(d => d.markup);

    const categoryArray = [...allLabels].reverse();

    const posData = [], negData = [];
    data.forEach((d, i) => {{
        const obj = {{ 
            lbl: allLabels[i], 
            val: allValues[i],
            articolo: d.articolo,
            descrizione: d.descrizione,
            prezzo: d.prezzo,
            costo: d.costo,
            quantita: d.quantita,
            imponibile: d.peso
        }};
        (d.markup >= 0 ? posData : negData).push(obj);
    }});

    const rowH   = 30;
    const height = Math.max(320, data.length * rowH + 130);

    const minV     = Math.min(...allValues);
    const maxV     = Math.max(...allValues);
    const span     = (maxV - minV) || 20;
    const padLeft  = Math.max(span * 0.22, 8);
    const padRight = Math.max(span * 0.22, 8);
    const xMin = minV - padLeft;
    const xMax = maxV + padRight;

    const mkTrace = (items, color, textColor) => ({{
        type: 'bar',
        orientation: 'h',
        x: items.map(d => d.val),
        y: items.map(d => d.lbl),
        marker: {{
            color,
            opacity: 0.82,
            line: {{ color: 'rgba(0,0,0,0.08)', width: 1 }}
        }},
        text: items.map(d => `${{d.val.toFixed(1)}}%`),
        textposition: 'outside',
        cliponaxis: false,
        constraintext: 'none',
        customdata: items.map(d => [d.articolo, d.descrizione, d.prezzo, d.costo, d.quantita, d.imponibile]),
        hovertemplate: '<b style="background-color: white; padding: 8px; border-radius: 4px; display: block;">%{{y}}</b><br>' +
                       '<b>Articolo:</b> %{{customdata[0]}}<br>' +
                       '<b>Descrizione:</b> %{{customdata[1]}}<br>' +
                       '<b>Prezzo:</b> € %{{customdata[2]:.2f}}<br>' +
                       '<b>Costo:</b> € %{{customdata[3]:.2f}}<br>' +
                       '<b>Quantità:</b> %{{customdata[4]}}<br>' +
                       '<b>Imponibile:</b> € %{{customdata[5]:,.2f}}<br>' +
                       '<b>Markup:</b> %{{x:.2f}}%<extra></extra>',
        textfont: {{ size: 11, color: textColor, family: 'Inter, sans-serif', weight: 600 }},
        showlegend: false
    }});

    const traces = [
        mkTrace(posData, COLOR_POS, '#065f46'),
        mkTrace(negData, COLOR_NEG, '#9f1239'),
    ];

    const layout = {{
        xaxis: {{
            title: {{ text: 'Markup (%)', font: {{ size: 12, color: '#5c7a99' }}, standoff: 10 }},
            range: [xMin, xMax],
            zeroline: true,
            zerolinecolor: '#0d2e52',
            zerolinewidth: 2,
            gridcolor: '#e8eef5',
            tickfont: {{ size: 11, color: '#5c7a99' }},
            ticksuffix: '%',
            fixedrange: false,
        }},
        yaxis: {{
            side: 'left',
            automargin: true,
            tickfont: {{ size: 11, color: '#0d2e52', family: 'Inter, sans-serif' }},
            gridcolor: '#e8eef5',
            fixedrange: true,
            categoryorder: 'array',
            categoryarray: categoryArray,
        }},
        barmode: 'overlay',
        height: height,
        margin: {{ l: 30, r: 60, t: 20, b: 55 }},
        paper_bgcolor: 'rgba(0,0,0,0)',
        plot_bgcolor: 'rgba(0,0,0,0)',
        font: {{ family: 'Inter, sans-serif' }},
        showlegend: false,
        hovermode: 'closest',
        bargap: 0.38,
        shapes: [{{
            type: 'line', x0: 0, x1: 0,
            y0: -0.5, y1: data.length - 0.5,
            line: {{ color: '#0d2e52', width: 1.5, dash: 'dot' }}
        }}]
    }};

    const config = {{
        responsive: true,
        displayModeBar: true,
        modeBarButtonsToRemove: ['select2d', 'lasso2d', 'autoScale2d'],
        toImageButtonOptions: {{ format: 'png', filename: 'markup_report', scale: 2 }}
    }};

    Plotly.newPlot('markup-chart', traces, layout, config);
}}

function applyFilters() {{
    const search     = document.getElementById('search-input').value.toLowerCase().trim();
    const sortVal    = document.getElementById('sort-select').value;
    const filterVal  = document.getElementById('filter-select').value;

    let data = RAW_DATA.filter(d => {{
        const matchText   = !search || d.etichetta.toLowerCase().includes(search);
        const matchFilter =
            filterVal === 'positive' ? d.markup >= 0 :
            filterVal === 'negative' ? d.markup < 0  : true;
        return matchText && matchFilter;
    }});

    data.sort((a, b) => {{
        if (sortVal === 'label-asc')  return a.etichetta.localeCompare(b.etichetta);
        if (sortVal === 'label-desc') return b.etichetta.localeCompare(a.etichetta);
        if (sortVal === 'value-asc')  return a.markup - b.markup;
        if (sortVal === 'value-desc') return b.markup - a.markup;
        return 0;
    }});

    currentData = data;
    computeStats(data);
    buildChart(data);
}}

function resetFilters() {{
    document.getElementById('search-input').value  = '';
    document.getElementById('sort-select').value   = 'value-desc';
    document.getElementById('filter-select').value = 'all';
    applyFilters();
}}

document.getElementById('search-input').addEventListener('input',  applyFilters);
document.getElementById('sort-select').addEventListener('change',  applyFilters);
document.getElementById('filter-select').addEventListener('change', applyFilters);

applyFilters();

window.addEventListener('resize', () => {{
    const el = document.getElementById('markup-chart');
    if (el && el.data) Plotly.Plots.resize(el);
}});
</script>
</body>
</html>"""

        result = html_template

