    for assoc_type in assoc_maps.keys():
        for chunk in chunked_list(deal_ids, 100):
            url = f"https://api.hubapi.com/crm/v4/associations/deals/{assoc_type}/batch/read"
            payload = {"inputs": [{"id": str(deal_id)} for deal_id in chunk]}
            response = SESSION.post(url, json=payload)
            if response.status_code == 200:
                results = response.json().get("results", [])
                assoc_maps[assoc_type].update(_parse_association_results(results))

    for deal in deals:
        deal_id = str(deal.get("id"))
        assoc = deal.get("associations") or {}
        companies_assoc = assoc.get("companies")
        line_items_assoc = assoc.get("line_items")
        companies_empty = not companies_assoc or (isinstance(companies_assoc, dict) and not companies_assoc.get("results"))
        line_items_empty = not line_items_assoc or (isinstance(line_items_assoc, dict) and not line_items_assoc.get("results"))

        if companies_empty and "companies" in assoc_maps:
            ids = assoc_maps["companies"].get(deal_id, [])
            assoc["companies"] = {"results": [{"id": cid} for cid in ids]}
        if line_items_empty and "line_items" in assoc_maps:
            ids = assoc_maps["line_items"].get(deal_id, [])
            assoc["line_items"] = {"results": [{"id": lid} for lid in ids]}
        deal["associations"] = assoc

def get_company_names(deals):
    company_data = {}
    company_ids = set()

    for d in deals:
        assoc = d.get("associations", {}).get("companies", {})
        results = assoc.get("results", []) if isinstance(assoc, dict) else []
        if results:
            company_ids.add(results[0].get("id"))

    company_ids = [cid for cid in company_ids if cid]
    if not company_ids:
        return company_data

    for chunk in chunked_list(company_ids, 100):
        url = "https://api.hubapi.com/crm/v3/objects/companies/batch/read"
        payload = {
            "properties": ["name"],
            "inputs": [{"id": str(company_id)} for company_id in chunk]
        }
        response = SESSION.post(url, json=payload)
        if response.status_code == 200:
            results = response.json().get("results", [])
            for item in results:
                company_id = item.get("id")
                name = item.get("properties", {}).get("name", "")
                if company_id:
                    company_data[company_id] = name
            for company_id in chunk:
                if company_id not in company_data:
                    company_data[company_id] = ""
        else:
            for company_id in chunk:
                company_data[company_id] = ""

    return company_data

def get_deal_products(deals):
    deal_products = {}
    deal_quantities = {}
    deal_to_line_items = {}
    all_line_item_ids = []

    for deal in deals:
        deal_id = deal.get("id")
        assoc = deal.get("associations", {}).get("line_items", {})
        results = assoc.get("results", []) if isinstance(assoc, dict) else assoc
        item_ids = []
        if results:
            for item in results:
                item_id = item.get("id") or item.get("toObjectId")
                if item_id:
                    item_ids.append(str(item_id))
        deal_to_line_items[deal_id] = item_ids
        all_line_item_ids.extend(item_ids)

    unique_line_item_ids = list(dict.fromkeys(all_line_item_ids))
    line_item_data = {}

    for chunk in chunked_list(unique_line_item_ids, 100):
        url = "https://api.hubapi.com/crm/v3/objects/line_items/batch/read"
        payload = {
            "properties": ["name", "hs_product_name", "quantity", "price", "amount"],
            "inputs": [{"id": str(item_id)} for item_id in chunk]
        }
        response = SESSION.post(url, json=payload)
        if response.status_code == 200:
            results = response.json().get("results", [])
            for item in results:
                item_id = item.get("id")
                props = item.get("properties", {})
                if item_id:
                    line_item_data[item_id] = {
                        "name": props.get("name") or props.get("hs_product_name", ""),
                        "quantity": props.get("quantity", "1")
                    }
        else:
            for item_id in chunk:
                if item_id not in line_item_data:
                    line_item_data[item_id] = {"name": "", "quantity": "1"}

    for deal in deals:
        deal_id = deal.get("id")
        products = []
        quantities = []
        for item_id in deal_to_line_items.get(deal_id, []):
            item = line_item_data.get(item_id, {})
            product_name = (item.get("name") or "").strip()
            quantity = item.get("quantity")
            if product_name:
                products.append(product_name)
                quantities.append(str(quantity if quantity is not None else "1"))
        deal_products[deal_id] = "; ".join(products) if products else ""
        deal_quantities[deal_id] = "; ".join(quantities) if quantities else ""

    return deal_products, deal_quantities

if __name__ == "__main__":
    deals = fetch_deals()
    if not deals:
        print("❗ Nessuna trattativa trovata.")
        exit()

    ensure_associations(deals)

    company_names = get_company_names(deals)
    deal_products, deal_quantities = get_deal_products(deals)

    # Aggiungi company_name, prodotti, quantità e applica transcodifica dealstage
    for deal in deals:
        deal_id = deal.get("id")

        # Aggiungi company_name
        assoc = deal.get("associations", {}).get("companies", {})
        results = assoc.get("results", []) if isinstance(assoc, dict) else []
        company_id = results[0].get("id") if results else None
        deal["company_name"] = company_names.get(company_id, "") if company_id else ""

        # Aggiungi prodotti e quantità dalle line_items, con fallback al campo campione
        deal["prodotti"] = deal_products.get(deal_id, "") or deal.get("campione", "")
        deal["quantita"] = deal_quantities.get(deal_id, "")

        # 🔄 Transcodifica dealstage da numero a testo
        dealstage_code = deal.get("dealstage", "")
        deal["dealstage"] = DEALSTAGE_MAPPING.get(dealstage_code, dealstage_code)

    df = pd.DataFrame(deals)

    # 🔄 CONVERSIONE IN MAIUSCOLO per tutti i campi di testo (esclusi i numerici)
    print("\n🔄 Conversione in MAIUSCOLO...")
    text_columns = ['dealname', 'dealstage', 'dealtype', 'description', 'pipeline', 'prodotti', 'company_name']
    for col in text_columns:
        if col in df.columns:
            df[col] = df[col].fillna('').astype(str).str.upper()

    if 'dealname' in df.columns:
        df = df[~df['dealname'].fillna('').str.slice(0, 4).str.contains('UP', regex=False)]

    forecast_values = pd.to_numeric(df['hs_forecast_probability'], errors='coerce') if 'hs_forecast_probability' in df.columns else None
    stage_values = pd.to_numeric(df['hs_deal_stage_probability'], errors='coerce') if 'hs_deal_stage_probability' in df.columns else None
    if forecast_values is not None or stage_values is not None:
        forecast_mask = pd.Series(False, index=df.index)
        stage_mask = pd.Series(False, index=df.index)
        if forecast_values is not None:
            forecast_mask = (forecast_values >= 99.9) & (forecast_values <= 100.1)
            forecast_mask |= (forecast_values >= 0.999) & (forecast_values <= 1.001)
        if stage_values is not None:
            stage_mask = (stage_values >= 99.9) & (stage_values <= 100.1)
            stage_mask |= (stage_values >= 0.999) & (stage_values <= 1.001)
        combined_mask = forecast_mask | stage_mask
        df = df.loc[combined_mask == False]

    # 📊 FORMATTAZIONE PROBABILITÀ in percentuale
    if 'hs_forecast_probability' in df.columns:
        df['hs_forecast_probability'] = df['hs_forecast_probability'].apply(
            lambda x: f"{float(x)*100:.1f}%" if pd.notna(x) and x != '' else ''
        )
    if 'hs_deal_stage_probability' in df.columns:
        df['hs_deal_stage_probability'] = df['hs_deal_stage_probability'].apply(
            lambda x: f"{float(x)*100:.1f}%" if pd.notna(x) and x != '' else ''
        )

    if 'createdate' in df.columns:
        createdate_raw = df['createdate']
        createdate_numeric = pd.to_numeric(createdate_raw, errors='coerce')
        createdate_from_numeric = pd.to_datetime(createdate_numeric, unit='ms', errors='coerce', utc=True)
        createdate_from_text = pd.to_datetime(createdate_raw, errors='coerce', utc=True)
        createdate_final = createdate_from_numeric.fillna(createdate_from_text)
        df['createdate'] = createdate_final.dt.tz_localize(None).dt.strftime('%d-%m-%Y').fillna('')

    if 'data_consegna' in df.columns:
        data_consegna_parsed = df['data_consegna'].apply(parse_date_value)
        data_consegna_final = pd.to_datetime(data_consegna_parsed, errors='coerce')
        df['data_consegna'] = data_consegna_parsed.apply(lambda d: d.strftime('%d-%m-%Y') if d else '')
        df = df.assign(_data_consegna_sort=data_consegna_final).sort_values(
            by=["_data_consegna_sort", "dealname"],
            na_position="last"
        ).drop(columns=["_data_consegna_sort"])

    # Seleziona solo le colonne da esportare
    export_fields = ['dealname', 'company_name', 'amount', 'data_consegna', 'createdate', 'dealstage', 'dealtype', 'description', 'pipeline', 'hs_forecast_probability', 'hs_deal_stage_probability', 'art14_trat', 'prodotti', 'quantita']

    # Assicura che tutte le colonne esistano anche se vuote
    for field in export_fields:
        if field not in df.columns:
            df[field] = ""

    df = df[export_fields]

    # 🖥️ PREVIEW DETTAGLIATA nel terminale
    total_products = 0
