def parse_date_value(value):
    if value is None:
        return None
    if isinstance(value, (int, float)):
        ts = int(value)
        if ts <= 0:
            return None
        return datetime.date.fromtimestamp(ts / 1000)
    s = str(value).strip()
    if not s:
        return None
    if s.isdigit():
        if len(s) == 8:
            try:
                return datetime.datetime.strptime(s, "%Y%m%d").date()
            except ValueError:
                return None
        ts = int(s)
        if ts <= 0:
            return None
        return datetime.date.fromtimestamp(ts / 1000)
    try:
        return datetime.date.fromisoformat(s[:10])
    except ValueError:
        pass
    for fmt in ("%d/%m/%Y", "%d-%m-%Y"):
        try:
            return datetime.datetime.strptime(s[:10], fmt).date()
        except ValueError:
            continue
    return None

def fetch_deals_legacy():
    all_deals = []
    url = "https://api.hubapi.com/crm/v3/objects/deals"
    params = {
        "limit": 100,
        "archived": "false",
        "properties": ",".join(DEAL_PROPERTIES),
        "associations": "companies,line_items"
    }

    today = datetime.date.today()
    while url:
        response = SESSION.get(url, params=params)
        if response.status_code != 200:
            print("❌ Errore:", response.status_code, response.text)
            break

        data = response.json()
        for deal in data.get("results", []):
            props = deal.get("properties", {}).copy()
            amount = float(props.get("amount", "0") or 0)
            data_consegna = props.get("data_consegna") or ""
            props["data_consegna"] = data_consegna

            consegna_date = parse_date_value(data_consegna)
            if not consegna_date:
                continue

            is_closed = str(props.get("hs_is_closed", "")).lower() == "true"
            is_closed_won = str(props.get("hs_is_closed_won", "")).lower() == "true"

            if amount > 0 and consegna_date > today and not is_closed and not is_closed_won:
                props["id"] = deal.get("id")
                props["associations"] = deal.get("associations", {})
                all_deals.append(props)

        url = data.get("paging", {}).get("next", {}).get("link")
        params = {}

    return all_deals

def fetch_deals():
    all_deals = []
    search_url = "https://api.hubapi.com/crm/v3/objects/deals/search"
    today = datetime.date.today()
    today_ms = int(datetime.datetime.combine(today, datetime.time.min).timestamp() * 1000)
