def chunked_list(items, size):
    for i in range(0, len(items), size):
        yield items[i:i + size]

def _parse_association_results(items):
    parsed = {}
    for item in items:
        from_id = None
        if isinstance(item, dict):
            from_id = (item.get("from", {}) or {}).get("id") or item.get("fromObjectId") or item.get("fromId")
        if not from_id:
            continue
        to_items = []
        if isinstance(item, dict):
            to_items = item.get("to") or item.get("results") or []
        ids = []
        for t in to_items:
            if isinstance(t, dict):
                tid = t.get("id") or t.get("toObjectId")
            else:
                tid = t
            if tid:
                ids.append(str(tid))
        parsed[str(from_id)] = ids
    return parsed

def ensure_associations(deals):
    deal_ids = [str(d.get("id")) for d in deals if d.get("id")]
    if not deal_ids:
        return

    missing_types = set()
    for deal in deals:
        assoc = deal.get("associations") or {}
        companies_assoc = assoc.get("companies")
        line_items_assoc = assoc.get("line_items")
        companies_empty = not companies_assoc or (isinstance(companies_assoc, dict) and not companies_assoc.get("results"))
        line_items_empty = not line_items_assoc or (isinstance(line_items_assoc, dict) and not line_items_assoc.get("results"))
        if companies_empty:
            missing_types.add("companies")
        if line_items_empty:
            missing_types.add("line_items")
    if not missing_types:
        return

    assoc_maps = {assoc_type: {} for assoc_type in missing_types}
    for assoc_type in assoc_maps.keys():
        for chunk in chunked_list(deal_ids, 100):
            url = f"https://api.hubapi.com/crm/v4/associations/deals/{assoc_type}/batch/read"
            payload = {"inputs": [{"id": str(deal_id)} for deal_id in chunk]}
            response = SESSION.post(url, json=payload)
            if response.status_code == 200:
                results = response.json().get("results", [])
                assoc_maps[assoc_type].update(_parse_association_results(results))

    for deal in deals:
        deal_id = str(deal.get("id"))
        assoc = deal.get("associations") or {}
        companies_assoc = assoc.get("companies")
