        line_items_empty = not line_items_assoc or (isinstance(line_items_assoc, dict) and not line_items_assoc.get("results"))

        if companies_empty and "companies" in assoc_maps:
            ids = assoc_maps["companies"].get(deal_id, [])
            assoc["companies"] = {"results": [{"id": cid} for cid in ids]}
        if line_items_empty and "line_items" in assoc_maps:
            ids = assoc_maps["line_items"].get(deal_id, [])
            assoc["line_items"] = {"results": [{"id": lid} for lid in ids]}
        deal["associations"] = assoc

def get_company_names(deals):
