        function updateStats() {
            const totalRows = currentData.length;
            const totalBudget = currentData.reduce((sum, row) => sum + row.BudgetMensile, 0);
            const avgWeight = totalRows > 0 ? (currentData.reduce((sum, row) => sum + row.Peso, 0) / totalRows).toFixed(2) : 0;

            document.getElementById('totalRows').textContent = totalRows;
            document.getElementById('totalBudget').textContent = '€ ' + totalBudget.toLocaleString('it-IT', {minimumFractionDigits: 2, maximumFractionDigits: 2});
            document.getElementById('avgWeight').textContent = avgWeight;
        }

