                renderTable();
                updateStats();
                showStatus('✅ Riga eliminata! Clicca "Salva nel DB" per confermare.', false);
            }
        }

        // Salva tutte le modifiche nel DB
        function saveAllChanges() {
            const btn = event.target;
            btn.disabled = true;
            btn.innerHTML = '<span class="loading"></span> Salvataggio...';

            // Invia i dati al backend per il salvataggio nel DB
            const payload = {
                action: 'save_all',
                data: currentData,
                timestamp: new Date().toISOString()
            };

            console.log('Invio dati al DB:', payload);

            // Simula salvataggio (in produzione, questo andrebbe a un endpoint API)
            setTimeout(() => {
