        // Esporta CSV
        function exportData() {
            let csv = 'Anno,Mese,NomeMese,Peso,BudgetMensile\\n';
            currentData.forEach(row => {
                csv += `${row.Anno},${row.Mese},"${row.NomeMese}",${row.Peso},${row.BudgetMensile}\\n`;
            });

            const blob = new Blob([csv], { type: 'text/csv;charset=utf-8;' });
            const link = document.createElement('a');
            const url = URL.createObjectURL(blob);
            link.setAttribute('href', url);
            link.setAttribute('download', 'BudgetMensile_' + new Date().toISOString().split('T')[0] + '.csv');
            link.style.visibility = 'hidden';
